1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_DISCOUNT = 15;
3	const BLOCK_SIZE = 3;
4	const FIRST_INSURANCE_RATE = 0.1;
5	const LOYALTY_DISCOUNT_RATE = 0.2;
6	const LOYALTY_YEARS_THRESHOLD = 2;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const HIGH_ENCHANTMENT_RATE = 0.3;
9	
10	const ITEM_BASE_PRICES: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const MAIN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion"]);
20	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
21	
22	type Item = { type: string; enchantment?: number };
23	type Customer = { yearsWithMHPCO?: number };
24	type Scenario = {
25	  customer?: Customer;
26	  steps: { op: string; items: Item[] }[];
27	};
28	
29	function countItemsByType(items: Item[]): Map<string, number> {
30	  const counts = new Map<string, number>();
31	  for (const item of items) {
32	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
33	  }
34	  return counts;
35	}
36	
37	function blockDiscountFor(type: string, count: number): number {
38	  const isComponent = COMPONENT_TYPES.has(type);
39	  const formsBlock = count === BLOCK_SIZE;
40	  return isComponent && formsBlock ? BLOCK_OF_THREE_DISCOUNT : 0;
41	}
42	
43	function basePremiumForGroup(type: string, count: number): number {
44	  return count * ITEM_BASE_PRICES[type] - blockDiscountFor(type, count);
45	}
46	
47	function computePolicyBase(items: Item[]): number {
48	  const itemCountsByType = countItemsByType(items);
49	  let basePremium = 0;
50	  for (const [type, count] of itemCountsByType.entries()) {
51	    basePremium += basePremiumForGroup(type, count);
52	  }
53	  return basePremium;
54	}
55	
56	function sumItemSurcharge(
57	  items: Item[],
58	  rate: number,
59	  applies: (item: Item) => boolean,
60	): number {
61	  return items
62	    .filter(applies)
63	    .reduce((sum, item) => sum + ITEM_BASE_PRICES[item.type] * rate, 0);
64	}
65	
66	function computeFirstInsuranceSurcharge(items: Item[]): number {
67	  return sumItemSurcharge(items, FIRST_INSURANCE_RATE, (item) =>
68	    MAIN_ITEM_TYPES.has(item.type),
69	  );
70	}
71	
72	function computeHighEnchantmentSurcharge(items: Item[]): number {
73	  return sumItemSurcharge(
74	    items,
75	    HIGH_ENCHANTMENT_RATE,
76	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
77	  );
78	}
79	
80	function computeLoyaltyDiscount(policyBase: number, customer: Customer): number {
81	  const years = customer.yearsWithMHPCO ?? 0;
82	  if (years >= LOYALTY_YEARS_THRESHOLD) {
83	    return policyBase * LOYALTY_DISCOUNT_RATE;
84	  }
85	  return 0;
86	}
87	
88	export function runScenario(scenario: unknown): unknown {
89	  const s = scenario as Scenario;
90	  const customer = s.customer ?? { yearsWithMHPCO: 0 };
91	  const items = s.steps[0].items;
92	
93	  const policyBase = computePolicyBase(items);
94	  const highEnchantment = computeHighEnchantmentSurcharge(items);
95	  const firstInsurance = computeFirstInsuranceSurcharge(items);
96	  const loyaltyDiscount = computeLoyaltyDiscount(policyBase, customer);
97	
98	  const premium = policyBase + highEnchantment + firstInsurance - loyaltyDiscount + PROCESSING_FEE;
99	  return { results: [{ premium }] };
100	}
